"use strict";(self.webpackChunkwangdoc=self.webpackChunkwangdoc||[]).push([[7949],{86436:(n,s,a)=>{a.r(s),a.d(s,{data:()=>e});const e={key:"v-1238bc4c",path:"/css-tutorial/block.html",title:"盒状模型",lang:"zh-CN",frontmatter:{summary:"盒状模型 width width: auto表示父元素提供的所有宽度（100%）。 max-width max-width设为none，可以让元素占满父元素的整个宽度。 overflow overflow属性指定如果元素的大小超出容器时的行为。 visible：默认值，表示溢出的部分可见; hidden：表示溢出的部分不可见; scroll：表示发生溢出时，",head:[["meta",{property:"og:url",content:"https://yzqbooks.github.io/wangdoc/wangdoc/css-tutorial/block.html"}],["meta",{property:"og:site_name",content:"wangdoc"}],["meta",{property:"og:title",content:"盒状模型"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-06T10:09:00.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-04-06T10:09:00.000Z"}]]},excerpt:"",headers:[{level:2,title:"width",slug:"width",children:[]},{level:2,title:"max-width",slug:"max-width",children:[]},{level:2,title:"overflow",slug:"overflow",children:[]},{level:2,title:"clip",slug:"clip",children:[]},{level:2,title:"clip-path",slug:"clip-path",children:[]},{level:2,title:"box-sizing",slug:"box-sizing",children:[]},{level:2,title:"object-fit",slug:"object-fit",children:[]}],git:{createdTime:164923974e4,updatedTime:164923974e4,contributors:[{name:"yzqdev",email:"yzqdev@outlook.com",commits:1}]},readingTime:{minutes:2.38,words:714},filePathRelative:"css-tutorial/block.md"}},79282:(n,s,a)=>{a.r(s),a.d(s,{default:()=>t});const e=(0,a(66252).uE)('<h1 id="盒状模型" tabindex="-1"><a class="header-anchor" href="#盒状模型" aria-hidden="true">#</a> 盒状模型</h1><h2 id="width" tabindex="-1"><a class="header-anchor" href="#width" aria-hidden="true">#</a> width</h2><p><code>width: auto</code>表示父元素提供的所有宽度（100%）。</p><h2 id="max-width" tabindex="-1"><a class="header-anchor" href="#max-width" aria-hidden="true">#</a> max-width</h2><p><code>max-width</code>设为<code>none</code>，可以让元素占满父元素的整个宽度。</p><h2 id="overflow" tabindex="-1"><a class="header-anchor" href="#overflow" aria-hidden="true">#</a> overflow</h2><p><code>overflow</code>属性指定如果元素的大小超出容器时的行为。</p><ul><li><code>visible</code>：默认值，表示溢出的部分可见</li><li><code>hidden</code>：表示溢出的部分不可见</li><li><code>scroll</code>：表示发生溢出时，会显示滚动条，用户可以拖动滚动条，看到溢出的部分</li></ul><h2 id="clip" tabindex="-1"><a class="header-anchor" href="#clip" aria-hidden="true">#</a> clip</h2><p><code>clip</code>规则指定元素超出容器大小时，具体显示哪个部分。它只对绝对定位（absolute）和固定定位（fixed）的元素有效。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token property">clip</span><span class="token punctuation">:</span> <span class="token function">rect</span><span class="token punctuation">(</span>0px<span class="token punctuation">,</span> 100px<span class="token punctuation">,</span> 100px<span class="token punctuation">,</span> 0px<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>react</code>函数四个参数的含义如下。</p><ul><li>第一个参数：剪切后的顶边距离容器的顶边的距离</li><li>第二个参数：剪切后的右边界距离容器的左边界的距离</li><li>第三个参数：剪切后的底边距离容器的顶边的距离</li><li>第四个参数：剪切后的左边界距离容器的左边界的距离</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token property">clip</span><span class="token punctuation">:</span> <span class="token function">rect</span><span class="token punctuation">(</span>auto 100px auto auto<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>该规则已经被废除，但是浏览器还是普遍支持。</p><h2 id="clip-path" tabindex="-1"><a class="header-anchor" href="#clip-path" aria-hidden="true">#</a> clip-path</h2><p><code>clip-path</code>是<code>clip</code>规则的继承者，用来剪切元素的大小。它对所有定位方式都适用。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token property">clip</span><span class="token punctuation">:</span> <span class="token function">rect</span><span class="token punctuation">(</span>110px<span class="token punctuation">,</span> 160px<span class="token punctuation">,</span> 170px<span class="token punctuation">,</span> 60px<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token comment">/* 等同于 */</span>\n<span class="token property">clip-path</span><span class="token punctuation">:</span> <span class="token function">inset</span><span class="token punctuation">(</span>10px 20px 30px 40px<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>clip-path</code>支持多种路径定义方式。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">.clip-me</span> <span class="token punctuation">{</span>\n\n  <span class="token comment">/* referencing path from an inline SVG &lt;clipPath&gt; */</span>\n  <span class="token property">clip-path</span><span class="token punctuation">:</span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span>#c1<span class="token punctuation">)</span></span><span class="token punctuation">;</span>\n\n  <span class="token comment">/* referencing path from external SVG */</span>\n  <span class="token property">clip-path</span><span class="token punctuation">:</span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span>path.svg#c1<span class="token punctuation">)</span></span><span class="token punctuation">;</span>\n\n  <span class="token comment">/* polygon */</span>\n  <span class="token property">clip-path</span><span class="token punctuation">:</span> <span class="token function">polygon</span><span class="token punctuation">(</span>5% 5%<span class="token punctuation">,</span> 100% 0%<span class="token punctuation">,</span> 100% 75%<span class="token punctuation">,</span> 75% 75%<span class="token punctuation">,</span> 75% 100%<span class="token punctuation">,</span> 50% 75%<span class="token punctuation">,</span> 0% 75%<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n  <span class="token comment">/* circle */</span>\n  <span class="token property">clip-path</span><span class="token punctuation">:</span> <span class="token function">circle</span><span class="token punctuation">(</span>30px at 35px 35px<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n  <span class="token comment">/* ellipse */</span>\n  <span class="token property">clip-path</span><span class="token punctuation">:</span> <span class="token function">ellipse</span><span class="token punctuation">(</span>65px 30px at 125px 40px<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n  <span class="token comment">/* inset-rectangle() may replace inset() ? */</span>\n  <span class="token comment">/* rectangle() coming in SVG 2 */</span>\n\n  <span class="token comment">/* rounded corners... not sure if a thing anymore */</span>\n  <span class="token property">clip-path</span><span class="token punctuation">:</span> <span class="token function">inset</span><span class="token punctuation">(</span>10% 10% 10% 10% round 20%<span class="token punctuation">,</span> 20%<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><h2 id="box-sizing" tabindex="-1"><a class="header-anchor" href="#box-sizing" aria-hidden="true">#</a> box-sizing</h2><p><code>box-sizing</code>指定盒状模型的宽度范围。</p><ul><li><code>border-box</code>：宽度包括padding和border</li><li><code>content-box</code>：默认值，只包括内容区的宽度，不包括padding和border</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">*, *:after, *:before</span> <span class="token punctuation">{</span>\n  <span class="token property">-webkit-box-sizing</span><span class="token punctuation">:</span> border-box<span class="token punctuation">;</span>\n  <span class="token property">-moz-box-sizing</span><span class="token punctuation">:</span> border-box<span class="token punctuation">;</span>\n  <span class="token property">box-sizing</span><span class="token punctuation">:</span> border-box<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="object-fit" tabindex="-1"><a class="header-anchor" href="#object-fit" aria-hidden="true">#</a> object-fit</h2><p><code>object-fit</code>命令指定一个元素的大小应该如何适应它的容器，主要用于图像。它可以取以下的值。</p><ul><li>fill：容器的宽度和高度就是元素的宽度和高度，会截去溢出的部分。</li><li>contain：元素会填满容器，不会改变长宽比，可能会有溢出。</li><li>cover：元素会填满容器，可能会改变长宽比，但不会有溢出。</li><li>none：元素不会改变的大小，具体的展示效果由默认算法决定</li><li>scale-down：展示效果会选择<code>none</code>或<code>contain</code>之中，对象尺寸较小的一个</li><li>inherit：使用父元素的值</li><li>initial：使用浏览器的默认值</li><li>unset：这个属性是<code>inherit</code>和<code>initial</code>的结合，如果该元素继承父元素，就采用<code>inherit</code>，否则采用<code>initial</code></li></ul>',27),p={},t=(0,a(83744).Z)(p,[["render",function(n,s){return e}]])},83744:(n,s)=>{s.Z=(n,s)=>{const a=n.__vccOpts||n;for(const[n,e]of s)a[n]=e;return a}}}]);